    body {
      background-color: #0a0a0a;
      font-family: 'DM Sans', sans-serif;
      color: #f0f0f0;
      -webkit-font-smoothing: antialiased;
    }

    .email-wrapper {
      max-width: 620px;
      margin: 0 auto;
      background: #0a0a0a;
    }

    /* HERO */
    .hero {
      background: linear-gradient(160deg, #111 0%, #1a1a1a 60%, #1a1500 100%);
      padding: 48px 40px 36px;
      text-align: center;
      border-bottom: 2px solid #f5a623;
      position: relative;
      overflow: hidden;
    }

    .hero::before {
      content: '';
      position: absolute;
      top: -60px; left: -60px;
      width: 220px; height: 220px;
      border-radius: 50%;
      background: radial-gradient(circle, rgba(245,166,35,0.08) 0%, transparent 70%);
    }

    .hero::after {
      content: '';
      position: absolute;
      bottom: -40px; right: -40px;
      width: 160px; height: 160px;
      border-radius: 50%;
      background: radial-gradient(circle, rgba(245,166,35,0.06) 0%, transparent 70%);
    }

    .logo-mark {
      display: inline-block;
      width: 56px; height: 56px;
      background: #f5a623;
      border-radius: 12px;
      line-height: 56px;
      font-size: 28px;
      margin-bottom: 20px;
      transform: rotate(-6deg);
    }

    .hero h1 {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 52px;
      letter-spacing: 3px;
      color: #ffffff;
      line-height: 1;
      margin-bottom: 8px;
    }

    .hero h1 span { color: #f5a623; }

    .hero .tagline {
      font-size: 13px;
      font-weight: 500;
      letter-spacing: 4px;
      text-transform: uppercase;
      color: #888;
      margin-top: 10px;
    }

    /* BADGE */
    .badge-bar {
      background: #f5a623;
      padding: 14px 40px;
      display: flex;
      align-items: center;
      justify-content: center;
    }

    .badge-bar span {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 18px;
      letter-spacing: 2px;
      color: #0a0a0a;
    }

    /* COUNTDOWN */
    .countdown-bar {
      background: #1a1a1a;
      border-bottom: 1px solid #222;
      padding: 28px 40px;
      text-align: center;
    }

    .countdown-bar p {
      font-size: 12px;
      letter-spacing: 3px;
      text-transform: uppercase;
      color: #666;
      margin-bottom: 16px;
    }

    .countdown-boxes {
      display: flex;
      justify-content: center;
      gap: 12px;
    }

    .count-box {
      background: #111;
      border: 1px solid #2a2a2a;
      border-top: 3px solid #f5a623;
      border-radius: 8px;
      padding: 16px 24px;
      min-width: 80px;
    }

    .count-number {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 42px;
      color: #f5a623;
      letter-spacing: 2px;
      line-height: 1;
    }

    .count-label {
      font-size: 10px;
      letter-spacing: 2px;
      text-transform: uppercase;
      color: #555;
      margin-top: 4px;
    }

    /* BODY */
    .body {
      padding: 40px 40px 32px;
      background: #111;
    }

    .greeting {
      font-size: 22px;
      font-weight: 600;
      color: #ffffff;
      margin-bottom: 12px;
    }

    .greeting span { color: #f5a623; }

    .intro {
      font-size: 15px;
      color: #aaa;
      line-height: 1.7;
      margin-bottom: 32px;
    }

    /* STATS CARD */
    .stats-card {
      background: #1a1a1a;
      border: 1px solid #2a2a2a;
      border-left: 4px solid #f5a623;
      border-radius: 12px;
      padding: 24px 28px;
      margin-bottom: 32px;
    }

    .stats-card h3 {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 13px;
      letter-spacing: 3px;
      color: #f5a623;
      text-transform: uppercase;
      margin-bottom: 20px;
    }

    .stat-row {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 12px 0;
      border-bottom: 1px solid #222;
    }

    .stat-row:last-child {
      border-bottom: none;
      padding-bottom: 0;
    }

    .stat-label {
      font-size: 12px;
      font-weight: 500;
      letter-spacing: 1px;
      text-transform: uppercase;
      color: #666;
    }

    .stat-value {
      font-size: 15px;
      font-weight: 600;
      color: #f0f0f0;
    }

    .stat-value.highlight {
      color: #f5a623;
      font-family: 'Bebas Neue', sans-serif;
      font-size: 18px;
      letter-spacing: 1px;
    }

    .status-pill {
      background: rgba(245,166,35,0.12);
      border: 1px solid rgba(245,166,35,0.3);
      color: #f5a623;
      font-size: 12px;
      font-weight: 600;
      letter-spacing: 2px;
      text-transform: uppercase;
      padding: 4px 12px;
      border-radius: 20px;
    }

    /* ALERT BOX */
    .alert-box {
      background: linear-gradient(135deg, #1a1500, #1f1a00);
      border: 1px solid #2e2600;
      border-radius: 10px;
      padding: 20px 24px;
      margin-bottom: 32px;
      display: flex;
      gap: 16px;
      align-items: flex-start;
    }

    .alert-icon { font-size: 28px; flex-shrink: 0; }

    .alert-text h4 {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 16px;
      letter-spacing: 2px;
      color: #f5a623;
      margin-bottom: 6px;
    }

    .alert-text p {
      font-size: 13px;
      color: #888;
      line-height: 1.6;
    }

    /* BENEFITS */
    .benefits-section { margin-bottom: 36px; }

    .section-title {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 22px;
      letter-spacing: 2px;
      color: #ffffff;
      margin-bottom: 16px;
      border-bottom: 1px solid #222;
      padding-bottom: 10px;
    }

    .benefit-item {
      display: flex;
      align-items: flex-start;
      gap: 14px;
      padding: 12px 0;
      border-bottom: 1px solid #1a1a1a;
    }

    .benefit-item:last-child { border-bottom: none; }

    .benefit-icon {
      width: 36px; height: 36px;
      background: rgba(245,166,35,0.1);
      border-radius: 8px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 16px;
      flex-shrink: 0;
    }

    .benefit-text {
      font-size: 14px;
      color: #bbb;
      line-height: 1.5;
      padding-top: 8px;
    }

    /* PRICE WARNING */
    .price-warning {
      background: rgba(200,241,53,0.05);
      border: 1px solid rgba(200,241,53,0.15);
      border-radius: 8px;
      padding: 14px 18px;
      margin-bottom: 32px;
      text-align: center;
    }

    .price-warning p {
      font-size: 13px;
      color: #aaa;
      line-height: 1.6;
    }

    .price-warning strong { color: #c8f135; }

    /* CTA */
    .cta-section {
      text-align: center;
      margin-bottom: 36px;
      background: linear-gradient(135deg, #0f1a0f, #141f14);
      border: 1px solid #1e2e1e;
      border-radius: 12px;
      padding: 32px 28px;
    }

    .cta-section h3 {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 26px;
      letter-spacing: 2px;
      color: #ffffff;
      margin-bottom: 8px;
    }

    .cta-section p {
      font-size: 13px;
      color: #888;
      margin-bottom: 24px;
      line-height: 1.6;
    }

    .cta-btn {
      display: inline-block;
      background: #c8f135;
      color: #0a0a0a;
      font-family: 'Bebas Neue', sans-serif;
      font-size: 20px;
      letter-spacing: 3px;
      text-decoration: none;
      padding: 18px 48px;
      border-radius: 6px;
      margin-bottom: 12px;
    }

    .cta-note {
      font-size: 11px;
      color: #555;
      margin-top: 10px;
    }

    /* SUPPORT */
    .support {
      font-size: 13px;
      color: #666;
      line-height: 1.8;
      margin-bottom: 32px;
      text-align: center;
    }

    .support a { color: #c8f135; text-decoration: none; }

    /* FOOTER */
    .footer {
      background: #0a0a0a;
      border-top: 1px solid #1a1a1a;
      padding: 28px 40px;
      text-align: center;
    }

    .footer-logo {
      font-family: 'Bebas Neue', sans-serif;
      font-size: 20px;
      letter-spacing: 3px;
      color: #333;
      margin-bottom: 12px;
    }

    .footer p {
      font-size: 11px;
      color: #444;
      line-height: 1.8;
    }

    .footer a { color: #666; text-decoration: none; }
    .divider { color: #333; margin: 0 6px; }
  </style>
</head>
<body>
<div class="email-wrapper">

  <!-- HERO -->
  <div class="hero">
    <div class="logo-mark">⏳</div>
    <h1>EXPIRING<br/><span>IN 3 DAYS</span></h1>
    <p class="tagline">World Flight Gym · Member Portal</p>
  </div>

  <!-- BADGE -->
  <div class="badge-bar">
    <span>⚠️ ACTION REQUIRED — RENEW BEFORE YOU LOSE ACCESS</span>
  </div>

  <!-- COUNTDOWN -->
  <div class="countdown-bar">
    <p>Your membership expires in</p>
    <div class="countdown-boxes">
      <div class="count-box">
        <div class="count-number">3</div>
        <div class="count-label">Days</div>
      </div>
      <div class="count-box">
        <div class="count-number">00</div>
        <div class="count-label">Hours</div>
      </div>
      <div class="count-box">
        <div class="count-number">00</div>
        <div class="count-label">Mins</div>
      </div>
    </div>
  </div>

  <!-- BODY -->
  <div class="body">

    <p class="greeting">Hey <span>{{ $('If').item.json.fields.Name }}</span>,</p>
    <p class="intro">
      This is a friendly heads-up — your World Flight Gym membership is expiring
      in just <strong style="color:#f5a623">3 days</strong>. Don't let your progress
      come to a halt. Renew now and keep the momentum going! 💪
    </p>

    <!-- STATS CARD -->
    <div class="stats-card">
      <h3>📋 Your Membership Details</h3>

      <div class="stat-row">
        <span class="stat-label">Member Name</span>
        <span class="stat-value">{{ $('If').item.json.fields.Name }}</span>
      </div>

      <div class="stat-row">
        <span class="stat-label">Current Plan</span>
        <span class="stat-value">{{ $('If').item.json.fields.Subscription }}</span>
      </div>

      <div class="stat-row">
        <span class="stat-label">Expiry Date</span>
        <span class="stat-value highlight">{{ $('If').item.json.fields['end date'] }}</span>
      </div>

      <div class="stat-row">
        <span class="stat-label">Status</span>
        <span class="status-pill">⚠️ EXPIRING SOON</span>
      </div>
    </div>

    <!-- ALERT -->
    <div class="alert-box">
      <div class="alert-icon">🔔</div>
      <div class="alert-text">
        <h4>DON'T LOSE YOUR STREAK</h4>
        <p>Once your membership expires, access to all facilities, classes, and the member app will be suspended immediately. Renew before <strong style="color:#f5a623">{{ $('If').item.json.fields['end date'] }}</strong> to avoid any interruption.</p>
      </div>
    </div>

    <!-- BENEFITS -->
    <div class="benefits-section">
      <h2 class="section-title">KEEP WHAT YOU'VE GOT</h2>

      <div class="benefit-item">
        <div class="benefit-icon">🏋️</div>
        <p class="benefit-text">Unlimited access to all gym facilities & equipment — 24/7</p>
      </div>

      <div class="benefit-item">
        <div class="benefit-icon">🧘</div>
        <p class="benefit-text">Group fitness classes & personal training sessions</p>
      </div>

      <div class="benefit-item">
        <div class="benefit-icon">📱</div>
        <p class="benefit-text">Full access to app, workout tracking & progress tools</p>
      </div>

      <div class="benefit-item">
        <div class="benefit-icon">🏷️</div>
        <p class="benefit-text">Exclusive member discounts, promotions & early event access</p>
      </div>
    </div>

    <!-- PRICE WARNING -->
    <div class="price-warning">
      <p>🔒 <strong>Renew now and lock in your current rate.</strong><br/>
      Prices may increase for new sign-ups — existing members who renew keep their plan pricing.</p>
    </div>

    <!-- CTA -->
    <div class="cta-section">
      <h3>RENEW IN UNDER 2 MINUTES 🚀</h3>
      <p>Click below to fill out your renewal form.<br/>Your membership will be extended immediately.</p>
      <a href="https://forms.fillout.com/t/cGxTECFjNMus?email={{ $('Search records').item.json.fields['Email address'] }}&name={{ $('If').item.json.fields.Name }}&plan={{ $('If').item.json.fields.Subscription }}" class="cta-btn">
        🔄 RENEW MY MEMBERSHIP NOW
      </a>
      <p class="cta-note">Takes less than 2 minutes · Secure form · Instant confirmation</p>
    </div>

    <!-- SUPPORT -->
    <p class="support">
      Questions about your plan? Contact us at
      <a href="mailto:[Support Email]">[Support Email]</a>
      or call <strong style="color:#aaa">[Phone Number]</strong><br/>
      Our team is available Mon–Sat, 7am – 9pm.
    </p>

  </div>

  <!-- FOOTER -->
  <div class="footer">
    <div class="footer-logo">⚡ WORLD FLIGHT GYM</div>
    <p>
      © 2026 World Flight Gym · [Gym Address]<br/>
      <a href="[Unsubscribe Link]">Unsubscribe</a>
      <span class="divider">·</span>
      <a href="[Privacy Policy]">Privacy Policy</a>
      <span class="divider">·</span>
      <a href="[Terms]">Terms of Service</a>
    </p>
  </div>

</div>
</body>
</html>

